import React from 'react';
import ReactDOM from 'react-dom';
import App from './components/App';

ReactDOM.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>,
  document.getElementById('root')
);

import React from 'react';

function App() {
  return (
    <div className="App">
      <header>
        <h1>Welcome to my React App!</h1>
      </header>
      <main>
        <p>This is a sample React application.</p>
      </main>
      <footer>
        <p>© 2022 My App. All rights reserved.</p>
      </footer>
    </div>
  );
}

export default App;

import React from 'react';

function Header() {
  return (
    <header>
      <h1>My React App Header</h1>
      <nav>
        <ul>
          <li><a href="#">Home</a></li>
          <li><a href="#">About</a></li>
          <li><a href="#">Contact</a></li>
        </ul>
      </nav>
    </header>
  );
}

export default Header;

import React from 'react';

function Footer() {
  return (
    <footer>
      <p>&copy; 2022 My React App. All rights reserved.</p>
    </footer>
  );
}

export default Footer;

import React from 'react';

function Sidebar() {
  return (
    <aside>
      <h2>Sidebar</h2>
      <ul>
        <li><a href="#">Item 1</a></li>
        <li><a href="#">Item 2</a></li>
        <li><a href="#">Item 3</a></li>
      </ul>
    </aside>
  );
}

export default Sidebar;

body {
  font-family: Arial, sans-serif;
  background-color: #f2f2f2;
  margin: 0;
  padding: 0;
}

.App {
  max-width: 800px;
  margin: 0 auto;
  padding: 20px;
  background-color: #ffffff;
  box-shadow: 0px 0px 5px rgba(0, 0, 0, 0.1);
}

header {
  background-color: #333333;
  color: #ffffff;
  padding: 20px;
}

h1 {
  margin: 0;
}

main {
  margin-top: 20px;
}

footer {
  background-color: #333333;
  color: #ffffff;
  padding: 10px;
  text-align: center;
}

ul {
  list-style-type: none;
  padding: 0;
}

ul li {
  margin-bottom: 10px;
}

a {
  color: #333333;
  text-decoration: none;
}

a:hover {
  text-decoration: underline;
}

aside {
  background-color: #f9f9f9;
  padding: 20px;
  border: 1px solid #dddddd;
}

h2 {
  margin-top: 0;
  margin-bottom: 10px;
}

/* CSS Reset */
html, body, div, span, object, iframe,
h1, h2, h3, h4, h5, h6, p, blockquote, pre,
a, abbr, address, cite, code,
del, dfn, em, img, ins, kbd, q, samp,
small, strong, sub, sup, var,
b, i,
dl, dt, dd, ol, ul, li,
fieldset, form, label, legend,
table, caption, tbody, tfoot, thead, tr, th, td {
  margin: 0;
  padding: 0;
  border: 0;
  font-weight: inherit;
  font-style: inherit;
  font-size: 100%;
  font-family: inherit;
  vertical-align: baseline;
}

/* HTML5 display-role reset for older browsers */
article, aside, details, figcaption, figure,
footer, header, hgroup, menu, nav, section {
  display: block;
}

body {
  line-height: 1;
}

ol, ul {
  list-style: none;
}

blockquote, q {
  quotes: none;
}

blockquote:before, blockquote:after,
q:before, q:after {
  content: '';
  content: none;
}

table {
  border-collapse: collapse;
  border-spacing: 0;
}

I apologize for the confusion earlier. Since we are working on a Linux terminal simulation, there is no direct command to modify the background color of a web page. However, assuming you have the necessary code in your React project, you can modify the CSS file to change the background color.

Please locate the specific CSS file that contains the styling for the background color and update the relevant CSS rule accordingly:

```
body {
  background-color: #000000;
}
```

Save the file, and the background color of your web page should be changed to black.
